const express = require('express');
const axios = require('axios');

const app = express();
const port = process.env.PORT || 3000;

app.use(express.json());

app.post('/verify-bvn', async (req, res) => {
  const { bvn } = req.body;

  if (!bvn) {
    return res.status(400).json({ error: 'BVN is required' });
  }

  const appId = process.env.PREMBLY_APP_ID;
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!appId || !apiKey) {
    return res.status(500).json({ error: 'Prembly credentials are not configured' });
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/bvn',
      { bvn },
      {
        headers: {
          'app-id': appId,
          'x-api-key': apiKey,
          'Content-Type': 'application/json'
        }
      }
    );

    res.status(response.status).json(response.data);
  } catch (error) {
    if (error.response) {
      // The request was made and the server responded with a status code
      // that falls out of the range of 2xx
      res.status(error.response.status).json(error.response.data);
    } else if (error.request) {
      // The request was made but no response was received
      res.status(503).json({ error: 'No response from Prembly API' });
    } else {
      // Something happened in setting up the request that triggered an Error
      res.status(500).json({ error: error.message });
    }
  }
});

app.listen(port, () => {
  console.log(`Server is running on port ${port}`);
});

